# E2-Skeptic three-route assess for S52-T1-A-E2
def assess(record: dict) -> str:
    required = {'metrics', 'baseline_frozen', 'jobs', 'stakeholders', 'case_id'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    try:
        ok = not (record["jobs"] == 0 or not record["baseline_frozen"])
    except Exception:
        return 'REOPEN_CF1'
    return 'PASS' if ok else 'REOPEN_CF1'

record = {"case_id": "CASO-PER-052-1A", **{"stakeholders":{"ops","relationship","privacy"},"jobs":3,"metrics":{"ttr","review_precision"},"baseline_frozen":True}}
valid = dict(record)
invalid = dict(valid)
# adverse: invert first boolean flag if any
_flipped=False
for _k,_v in list(invalid.items()):
    if isinstance(_v,bool):
        invalid[_k]= (not _v)
        _flipped=True
        break
if not _flipped and isinstance(invalid.get('stages'), list):
    invalid['stages']=list(reversed(invalid['stages']))
elif not _flipped and 'dependencies' in invalid:
    invalid['dependencies']=[["domain","infrastructure"]]
incomplete={k:v for k,v in valid.items() if k != 'baseline_frozen'}
print(assess(valid), assess(invalid), assess(incomplete))

